const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
let story_arc_prompt = '';
let story_arc_name = '';
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value&user_id=eq.${encodeURIComponent(userId)}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
  }
} catch (e) {
  if (!recipient_email) recipient_email = 'eric@agileadtesting.com';
}

// Load story arc from story_arcs table if specified (public table — no user_id filter)
const requestedArc = (trigger.story_arc || '').trim();
if (requestedArc) {
  try {
    const arcs = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/story_arcs_v2?name=ilike.*${encodeURIComponent(requestedArc)}*&limit=1`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    if (Array.isArray(arcs) && arcs.length > 0) {
      story_arc_prompt = arcs[0].prompt_text;
      story_arc_name = arcs[0].name;
    }
  } catch (e) {}
}

// Fallback: if no arc specified or not found, load default from app_config
if (!story_arc_prompt) {
  try {
    const cfgRows = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=eq.story_structure_guidelines&select=key,value&limit=1&user_id=eq.${encodeURIComponent(userId)}`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    if (Array.isArray(cfgRows) && cfgRows.length > 0) story_arc_prompt = cfgRows[0].value;
  } catch (e) {}
}

return [{ json: { SUPABASE_URL, SUPABASE_API_KEY, userId, recipient_email, bcc_email: bcc_email || '', story_arc_prompt, story_arc_name } }];

const trigger = $('workflow_trigger').first().json;
const genre = $('get_genre_config').first().json;
const genreData = Array.isArray(genre) ? genre[0] : genre;
const research = $('research_concept').first().json.message || '';
const chapterCount = parseInt(trigger.target_chapter_count) || 10;
const storyArcPrompt = $('settings').first().json.story_arc_prompt || '';
const storyArcName = $('settings').first().json.story_arc_name || '';
const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const userId = $('settings').first().json.userId || '';

// Check for existing outline (this is a revision if one exists)
let existingOutline = null;
let isRevision = false;
const projectTitle = trigger.project_title || '';
if (projectTitle) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/writing_projects_v2?title=eq.' + encodeURIComponent(projectTitle) + '&select=outline&limit=1&user_id=eq.' + encodeURIComponent(userId),
      headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey }
    });
    if (Array.isArray(resp) && resp.length > 0 && resp[0].outline && Object.keys(resp[0].outline).length > 0) {
      existingOutline = resp[0].outline;
      isRevision = true;
    }
  } catch (e) {}
}

let existingOutlineSection = '';
if (isRevision && existingOutline) {
  const charList = (existingOutline.characters || []).map(c => '- ' + c.name + ' (' + c.role + '): ' + (c.description || c.arc || '')).join('\n');
  const chapList = (existingOutline.chapters || []).map(ch => (ch.number || '?') + '. ' + ch.title + ': ' + ch.brief).join('\n');
  existingOutlineSection = `\n\n## EXISTING OUTLINE (THIS IS A REVISION)\nThis story already has an outline. You are REVISING it, not creating from scratch.\n\n### ⚠️ CHARACTER LOCK — DO NOT MODIFY ⚠️\nThe following characters are LOCKED. You MUST include every single one of them in your revised outline with the SAME name, SAME role, and SAME arc description. Do NOT rename, merge, remove, replace, or rewrite any character. Do NOT change their role (Protagonist stays Protagonist, Antagonist stays Antagonist, etc.). The ONLY permitted character changes are:\n- Adding NEW characters that the user explicitly requests\n- Removing a character ONLY if the user explicitly says to remove them by name\n- Modifying a character ONLY if the user explicitly names that character and describes the change\n\nIf the user asks to change the story arc, timeline, setting, chapter count, or plot structure, you MUST adapt the plot to fit these LOCKED characters — never the other way around.\n\n### LOCKED CHARACTERS (COPY THESE EXACTLY INTO YOUR OUTPUT)\n${charList}\n\n### Existing Premise\n${existingOutline.premise || ''}\n\n### Existing Themes\n${Array.isArray(existingOutline.themes) ? existingOutline.themes.join(', ') : (existingOutline.themes || '')}\n\n### Existing Chapter Structure (may be restructured per user request)\n${chapList}\n`;
}

const assignmentVerb = isRevision ? 'Revise the existing outline' : 'Create a detailed outline';

const prompt = `You are a master storyteller and book architect.

## Genre: ${genreData?.genre_name || 'Fiction'}
## Genre Guidelines: ${genreData?.writing_guidelines || ''}

## Writing Prime Directive
Write like a human, not a machine. Use clear, everyday language and short sentences. Cut cliches — no revolutionize, game-changing, unleash, or delve. Get to the point — remove filler words. No hype, just facts. Be genuine. Show, don't tell — use concrete examples instead of vague claims. Stay focused. Keep descriptions tight. Respect the reader's intelligence. Write like you'd pitch a story to a smart friend. Skip unnecessary adjectives and adverbs.

## Story Arc Framework${storyArcName ? ' — ' + storyArcName : ''}
You MUST use this story arc framework to structure the outline. Follow its acts, beats, and structural requirements exactly:

${storyArcPrompt}

## Research
${research}${existingOutlineSection}

## Assignment
${assignmentVerb} for "${projectTitle || 'Untitled'}".

Core concept / revision instructions: ${trigger.initial_concept}
Themes: ${trigger.themes || 'To be determined'}
Target chapters/sections: ${chapterCount}

## Requirements
Apply the Story Arc Framework above to design the plot. Follow the specified arc structure exactly — use its acts, beats, and structural requirements to shape every section of the outline. Include:
1. story_arc_name: the name of the story arc framework being used (exactly: "${storyArcName || 'Three-Act Structure'}")
2. A refined title and one-paragraph premise
3. Core themes (3-5)
4. Character profiles with clearly assigned roles (Protagonist, Antagonist, Dynamic, Static) with name, role, arc, and description${isRevision ? ' — START by copying every LOCKED CHARACTER from above exactly as listed (same name, role, arc), then add any new characters the user requested' : ''}
5. Section/chapter breakdown with:
   - Number and title (use 0 for Prologue, 1-N for chapters, and N+1 for Epilogue)
