Return as JSON matching the output schema exactly.${isRevision ? '\n\n## FINAL CHECK — CHARACTER VERIFICATION\nBefore returning your JSON, verify that EVERY character listed in LOCKED CHARACTERS above appears in your output characters array with the same name and role. If any locked character is missing or renamed, you have made an error — go back and fix it. New characters may be added, but locked characters must never be removed or replaced.' : ''}`;

return [{ json: { prompt } }];

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const userId = $('settings').first().json.userId || '';
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Prefer': 'return=representation' };
const readHeaders = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };
const trigger = $('workflow_trigger').first().json;
const outline = $input.first().json.output || {};
// Inject story arc name into the outline so write_chapter knows which arc to follow
const storyArcName = $('settings').first().json.story_arc_name || outline.story_arc_name || 'Three-Act Structure';
outline.story_arc_name = storyArcName;
const title = outline.title || trigger.project_title || 'Untitled';
const genreSlug = trigger.genre_slug;

// Try to find existing project
let project = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects_v2?title=eq.' + encodeURIComponent(title) + '&limit=1&user_id=eq.' + encodeURIComponent(userId),
    headers: readHeaders
  });
  if (Array.isArray(resp) && resp.length > 0 && resp[0].id) project = resp[0];
} catch (e) {}

if (project) {
  // Snapshot the existing outline before overwriting
  if (project.outline && Object.keys(project.outline).length > 0) {
    try {
      // Get current max version number
      const verResp = await this.helpers.httpRequest({
        method: 'GET',
        url: supabaseUrl + '/rest/v1/outline_versions_v2?project_id=eq.' + project.id + '&order=version_number.desc&limit=1&select=version_number&user_id=eq.' + encodeURIComponent(userId),
        headers: readHeaders
      });
      const maxVersion = (Array.isArray(verResp) && verResp.length > 0) ? verResp[0].version_number : 0;
      // Save snapshot of the PREVIOUS outline
      await this.helpers.httpRequest({
        method: 'POST',
        url: supabaseUrl + '/rest/v1/outline_versions_v2',
        headers,
        body: {
          project_id: project.id,
          version_number: maxVersion + 1,
          outline: project.outline,
          revision_note: 'Auto-snapshot before revision',
          user_id: userId
        }
      });
    } catch (e) { /* outline_versions table may not exist yet — continue */ }
  }
  // MERGE: preserve existing chapter_outline data that the new outline doesn't include
  if (project.outline && project.outline.chapters && outline.chapters) {
    const existingChapters = {};
    for (const ch of project.outline.chapters) {
      if (ch.chapter_outline && ch.chapter_outline.sub_chapters && ch.chapter_outline.sub_chapters.length > 0) {
        existingChapters[ch.number] = ch.chapter_outline;
      }
    }
    for (const ch of outline.chapters) {
      if (!ch.chapter_outline || !ch.chapter_outline.sub_chapters || ch.chapter_outline.sub_chapters.length === 0) {
        if (existingChapters[ch.number]) {
          ch.chapter_outline = existingChapters[ch.number];
        }
      }
    }
  }

  // Update existing project with merged outline
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/writing_projects_v2?id=eq.' + project.id + '&user_id=eq.' + encodeURIComponent(userId),
    headers,
    body: { outline: outline, genre_slug: genreSlug, updated_at: new Date().toISOString() }
  });
} else {
  // Create new project
  const created = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/writing_projects_v2',
    headers,
    body: { title, genre_slug: genreSlug, project_type: 'story', status: 'outlined', outline: outline, chapter_count: (outline.chapters || []).length, user_id: userId }
  });
  project = Array.isArray(created) ? created[0] : created;
}

// Trigger embedding pipeline (async, don't wait)
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/rpc/match_writing_documents',
    headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' },
    body: JSON.stringify({ query_embedding: Array(1536).fill(0), match_count: 0 })
  });
} catch (e) { /* just testing connection */ }

return [{ json: { outline, project_id: project?.id || null, title, embed_needed: true } }];

